import React from 'react'
import { Button, Space, Avatar } from 'antd';
import AWBGenerationIcon from '../../images/awb_generation_icon.svg';
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';

const containerConstants = containerConstantsService.getInstance();

const AWBEmptyDataView = ({ showButtons, heading, description, ...otherProps }) => {

    const openDefaultAWBForm = () => {
        otherProps.setShowFormModalDialog(
            {
                visible: true,
                okText: containerConstants.formatString(containerConstants.ADD),
                title: containerConstants.formatString(containerConstants.ADD_DEFAULT_AWB)
            });
    }
    return (
        <div id='awb-empty-data-view'
            style={{ margin: showButtons === 'first' ? '23px 0 0' : '67px 0 0' }}
        >
            <Avatar src={AWBGenerationIcon} shape='square' />
            <h1>{heading}</h1>
            <p>{description}</p>
            {(showButtons === 'both' || showButtons === 'first') &&
                <Space align='center'
                    style={{ marginBottom: showButtons === 'first' ? '4px' : '48px' }} >
                    <Button
                        ghost
                        type="primary"
                        onClick={openDefaultAWBForm}
                    >
                        {containerConstants.formatString(containerConstants.ADD_DEFAULT_AWB)}
                    </Button>
                    {showButtons !== 'first' &&
                        <Button
                            style={{ color: '#FFFFFF' }}
                            type="primary"
                            onClick={() => otherProps.setShowModalDialogAddUpload(true)}
                        >
                            {containerConstants.formatString(containerConstants.ADD_AWB)}
                        </Button>}
                </Space>}
        </div>
    )
}

export default AWBEmptyDataView;
